async (params, browser) => {
  // Open business page
  await browser.open(`${params.business_url}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*=\'businessName\']', 15000)

  await browser.wait(2000)

  // Scroll to reviews
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(2000)

  // Scroll through reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewEls = document.querySelectorAll('[class*="review"][class*="margin"], [class*="review__"], [data-review-id], #reviews > section > div > div > ul > li'); for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('[class*="user-passport"] a, a[href*="/user_details"], [class*="author"]'); const ratingEl = el.querySelector('[class*="star"][aria-label], [role="img"][aria-label*="star"]'); const contentEl = el.querySelector('[class*="comment"], [class*="review-content"] p, p[lang]'); const dateEl = el.querySelector('[class*="date"], span[class*="css"]'); const usefulEl = el.querySelector('[class*="useful"]'); const funnyEl = el.querySelector('[class*="funny"]'); const coolEl = el.querySelector('[class*="cool"]'); if (contentEl || authorEl) { reviews.push({ author: authorEl ? authorEl.textContent.trim() : 'Anonymous', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', content: contentEl ? contentEl.textContent.trim().substring(0, 800) : '', date: dateEl ? dateEl.textContent.trim() : '', useful: usefulEl ? usefulEl.textContent.trim() : '', funny: funnyEl ? funnyEl.textContent.trim() : '', cool: coolEl ? coolEl.textContent.trim() : '' }); } } const overallRatingEl = document.querySelector('[class*="star"][aria-label*="star"]'); const totalReviewsEl = document.querySelector('[class*="reviewCount"]'); return { overall_rating: overallRatingEl ? overallRatingEl.getAttribute('aria-label') || '' : '', total_reviews: totalReviewsEl ? totalReviewsEl.textContent.trim() : '', scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
